eval(__webpack_require__.ts("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   PREP_VAULT: function() { return /* binding */ PREP_VAULT; }\n/* harmony export */ });\n// frontend/src/data/prepVault.ts\n// Extracted verbatim from career-os-v2.html — do not strip embedded HTML.\n// The pv-formula, pv-trap, pv-def, pv-tree, pv-table, pv-tip CSS classes\n// in the content strings are rendered directly as innerHTML in React components.\nconst PREP_VAULT = {\n    dj: {\n        title: \"Preparation Vault — AAIA + AIGP (DJ)\",\n        sub: \"Pre-built reference for ISACA AAIA (March 2026) and IAPP AIGP — definitions, formulas, frameworks, exam traps\",\n        quickTopics: [\n            \"NIST AI RMF Core Functions\",\n            \"ISO 42001 vs ISO 27001\",\n            \"EU AI Act Risk Tiers\",\n            \"AI Model Drift Types\",\n            \"FAIR Quantification Formulas\",\n            \"SOC 2 vs SOC 1 Differences\",\n            \"Compensating Controls Analysis\",\n            \"AI Bias Metrics\"\n        ],\n        sections: [\n            {\n                id: \"aaia-governance\",\n                icon: \"\\uD83C\\uDFDB️\",\n                title: \"AI Governance Frameworks\",\n                weight: \"critical\",\n                subtitle: \"NIST AI RMF \\xb7 ISO 42001 \\xb7 OECD Principles \\xb7 EU AI Act — Domain 1 AAIA\",\n                category: \"AI Governance\",\n                tag: \"formula\",\n                subsections: [\n                    {\n                        heading: \"NIST AI RMF — Four Core Functions\",\n                        content: '\\n<div class=\"pv-def\"><strong>GOVERN</strong> — Establishes organization-wide policies, accountability structures, and culture for responsible AI. Sets risk tolerances, assigns roles, integrates AI risk into enterprise risk management. <em>The foundation all other functions rest on.</em></div>\\n<div class=\"pv-def\"><strong>MAP</strong> — Identifies context, stakeholders, and AI risks before deployment. Categorizes system purpose, potential impacts, and risk tolerances. Produces risk context documentation.</div>\\n<div class=\"pv-def\"><strong>MEASURE</strong> — Analyzes and assesses AI risks using quantitative and qualitative tools. Includes bias testing, performance monitoring, drift detection, and red-teaming. Ongoing throughout lifecycle.</div>\\n<div class=\"pv-def\"><strong>MANAGE</strong> — Prioritizes and responds to identified AI risks. Includes risk treatment decisions, incident response, remediation, and stakeholder communication. Continuous feedback into GOVERN.</div>\\n<div class=\"pv-formula\">\\n  <div class=\"pv-formula-title\">AI RMF Risk Calculation Framework</div>\\n  <div class=\"pv-formula-math\">AI Risk = Likelihood of Harm \\xd7 Severity \\xd7 Breadth of Impact\\nResidual Risk = Inherent Risk − (Control Effectiveness \\xd7 Coverage)\\nRisk Appetite Threshold → triggers Manage function response</div>\\n  <div class=\"pv-formula-example\">Example: High-stakes hiring AI. Likelihood: 0.7 (historical bias data). Severity: HIGH (employment impact). Breadth: 10,000 applicants/yr → triggers mandatory MEASURE controls.</div>\\n</div>'\n                    },\n                    {\n                        heading: \"Framework Comparison — NIST AI RMF vs ISO 42001 vs EU AI Act\",\n                        content: '\\n<table class=\"pv-table\">\\n  <thead><tr><th>Dimension</th><th>NIST AI RMF</th><th>ISO 42001</th><th>EU AI Act</th></tr></thead>\\n  <tbody>\\n    <tr><td>Type</td><td>Voluntary framework</td><td>Certifiable standard</td><td>Binding regulation</td></tr>\\n    <tr><td>Jurisdiction</td><td>US-focused, global adoption</td><td>Global</td><td>EU + extraterritorial</td></tr>\\n    <tr><td>Enforcement</td><td>None (voluntary)</td><td>Third-party audit</td><td>Fines up to €35M / 7% revenue</td></tr>\\n    <tr><td>Core structure</td><td>Govern/Map/Measure/Manage</td><td>PDCA management system</td><td>Risk tiers + prohibited acts</td></tr>\\n    <tr><td>Audit hook</td><td>Measure function</td><td>Clause 9: Performance evaluation</td><td>Article 9: Risk management system</td></tr>\\n    <tr class=\"pv-row-critical\"><td>Exam weight (AAIA)</td><td>★★★★★ Very high</td><td>★★★★ High</td><td>★★★★ High</td></tr>\\n  </tbody>\\n</table>'\n                    },\n                    {\n                        heading: \"Exam Traps — Governance Questions\",\n                        content: '\\n<div class=\"pv-trap\"><strong>TRAP #1:</strong> \"NIST AI RMF is mandatory for all US federal agencies.\" → <strong>FALSE.</strong> AI RMF is voluntary for all organizations. Only OMB M-24-10 mandates certain AI governance actions for federal agencies — not the AI RMF itself. Exam frequently conflates these.</div>\\n<div class=\"pv-trap\"><strong>TRAP #2:</strong> \"ISO 42001 replaces ISO 27001 for AI systems.\" → <strong>FALSE.</strong> ISO 42001 addresses AI management systems; ISO 27001 addresses information security. They are complementary and often implemented together. AI systems processing personal data need both.</div>\\n<div class=\"pv-trap\"><strong>TRAP #3:</strong> \"The EU AI Act applies only to AI developers in the EU.\" → <strong>FALSE.</strong> It has extraterritorial reach — any organization deploying AI whose outputs are used in the EU must comply, regardless of where they are headquartered.</div>\\n<div class=\"pv-trap\"><strong>TRAP #4:</strong> \"GOVERN is the last NIST AI RMF function, applied after implementation.\" → <strong>FALSE.</strong> GOVERN is implemented first and operates continuously — it sets the policy infrastructure that all other functions execute within.</div>'\n                    }\n                ]\n            },\n            {\n                id: \"aaia-risk\",\n                icon: \"⚖️\",\n                title: \"AI Risk Assessment & Quantification\",\n                weight: \"critical\",\n                subtitle: \"FAIR model \\xb7 Risk scoring \\xb7 Residual risk \\xb7 Loss event frequency — Domain 2 AAIA\",\n                category: \"AI Risk\",\n                tag: \"formula\",\n                subsections: [\n                    {\n                        heading: \"FAIR Risk Quantification — Full Formula Set\",\n                        content: '\\n<div class=\"pv-formula\">\\n  <div class=\"pv-formula-title\">FAIR Core Decomposition</div>\\n  <div class=\"pv-formula-math\">Risk = Loss Event Frequency (LEF) \\xd7 Loss Magnitude (LM)\\nLEF = Threat Event Frequency (TEF) \\xd7 Vulnerability (Vuln %)\\nLM = Primary Loss + Secondary Loss\\nPrimary Loss = Productivity + Response + Replacement + Fines/Judgments\\nSecondary Loss = Reputation + Competitive Advantage + Regulatory</div>\\n  <div class=\"pv-formula-example\">Example: Healthcare AI breach — TEF: 1.5/yr, Vuln: 40% → LEF: 0.6/yr. LM per event: $18M (100K records \\xd7 $180). ALE = 0.6 \\xd7 $18M = $10.8M/yr</div>\\n</div>\\n<div class=\"pv-formula\">\\n  <div class=\"pv-formula-title\">EU AI Act Risk Tier Classification</div>\\n  <div class=\"pv-formula-math\">Tier 1 — PROHIBITED: Social scoring, real-time biometric surveillance (public spaces), emotion recognition (workplace/education)\\nTier 2 — HIGH RISK: Hiring/firing, credit scoring, medical devices, law enforcement, critical infrastructure, education\\nTier 3 — LIMITED RISK: Chatbots, deepfakes → transparency obligations only\\nTier 4 — MINIMAL RISK: Spam filters, AI in video games → no obligations</div>\\n  <div class=\"pv-formula-example\">Exam tip: \"Hiring AI\" → always HIGH RISK. \"Customer service chatbot\" → LIMITED RISK (transparency req only). Know the exact tier for 8 key use cases.</div>\\n</div>'\n                    },\n                    {\n                        heading: \"AI Drift Detection — Diagnostic Framework\",\n                        content: '\\n<div class=\"pv-def\"><strong>Data Drift</strong> — Input feature distributions shift from training data. ALL metrics degrade uniformly. Cause: population change, data pipeline issues. Detection: PSI (Population Stability Index) &gt; 0.2 = significant drift.</div>\\n<div class=\"pv-def\"><strong>Concept Drift</strong> — The relationship between features and target variable changes. Diagnostic signature: <em>accuracy stays stable, precision/recall collapse</em> (masked by class imbalance). Cause: fraud pattern evolution, behavioral shifts. Most common exam question.</div>\\n<div class=\"pv-def\"><strong>Prediction Drift</strong> — Output distribution shifts without corresponding ground truth change. Detectable before labels are available. Often first signal of upstream data drift.</div>\\n<div class=\"pv-formula\">\\n  <div class=\"pv-formula-title\">Drift Diagnostic Decision Tree</div>\\n  <div class=\"pv-formula-math\">All metrics drop uniformly → Data Drift\\nPrecision/Recall drop, Accuracy stable → Concept Drift (imbalanced class)\\nOutput distribution shifts, inputs stable → Prediction Drift\\nRandom errors, no pattern → Pipeline/infrastructure issue</div>\\n</div>\\n<div class=\"pv-trap\"><strong>TRAP:</strong> \"Stable accuracy means the model is performing well.\" → In highly imbalanced datasets (fraud ~1%), predicting the majority class exclusively gives ~99% accuracy. Always evaluate precision AND recall together. Accuracy alone is meaningless for imbalanced classes.</div>'\n                    }\n                ]\n            },\n            {\n                id: \"aaia-audit\",\n                icon: \"\\uD83D\\uDD0D\",\n                title: \"AI Audit Methodology & Evidence\",\n                weight: \"high\",\n                subtitle: \"Audit procedures \\xb7 Evidence standards \\xb7 Control testing \\xb7 Reporting — Domain 5 AAIA\",\n                category: \"AI Audit\",\n                tag: \"trap\",\n                subsections: [\n                    {\n                        heading: \"AI Audit Lifecycle — Phases and Key Deliverables\",\n                        content: '\\n<div class=\"pv-tree\">AI AUDIT LIFECYCLE\\n├── PHASE 1: PLANNING\\n│   ├── Define AI system scope + inventory\\n│   ├── Stakeholder mapping (developer, deployer, affected parties)\\n│   ├── Risk assessment → prioritize audit procedures\\n│   └── Deliverable: AI Audit Plan + Risk Assessment\\n│\\n├── PHASE 2: FIELDWORK\\n│   ├── Model card review (purpose, training data, limitations)\\n│   ├── Bias testing (disparate impact analysis, group fairness metrics)\\n│   ├── Drift monitoring controls assessment\\n│   ├── Access controls for model training environment\\n│   ├── Change management for model updates\\n│   └── Deliverable: Workpapers + Evidence Matrix\\n│\\n├── PHASE 3: EVALUATION\\n│   ├── Control gap analysis (design vs operating effectiveness)\\n│   ├── Risk rating (Critical/High/Medium/Low)\\n│   ├── Compensating control assessment\\n│   └── Deliverable: Finding Sheets + Management Response\\n│\\n└── PHASE 4: REPORTING\\n    ├── Audit report with risk-prioritized findings\\n    ├── Root cause analysis per finding\\n    ├── Management action plans with owners + due dates\\n    └── Deliverable: Final Audit Report → Audit Committee</div>'\n                    },\n                    {\n                        heading: \"Compensating Controls — Assessment Framework\",\n                        content: '\\n<div class=\"pv-def\"><strong>Compensating Control</strong> — An alternative control that provides equivalent assurance to the primary control when the primary cannot be implemented. Must: (1) address the same risk, (2) provide comparable rigor, (3) be formally documented, and (4) be tested separately.</div>\\n<table class=\"pv-table\">\\n  <thead><tr><th>Primary Control Missing</th><th>Adequate Compensating Control</th><th>Insufficient Compensating</th><th>Finding Severity</th></tr></thead>\\n  <tbody>\\n    <tr><td>Automated bias monitoring</td><td>Monthly manual review + quarterly 3rd-party audit + complaint tracking</td><td>Annual self-assessment only</td><td>MEDIUM (detection gap)</td></tr>\\n    <tr class=\"pv-row-high\"><td>Change management approval</td><td>Documented emergency procedure + retrospective approval within 24hrs</td><td>Verbal approval only</td><td>HIGH (undocumented)</td></tr>\\n    <tr class=\"pv-row-critical\"><td>Model access controls</td><td>None acceptable — access controls have no adequate compensating control</td><td>Any manual process</td><td>CRITICAL (no equiv.)</td></tr>\\n    <tr><td>Drift alerting</td><td>Weekly manual metric review with documented thresholds and sign-off</td><td>Ad hoc review with no schedule</td><td>MEDIUM</td></tr>\\n  </tbody>\\n</table>\\n<div class=\"pv-tip\"><strong>TIP:</strong> The AAIA exam always provides 3 compensating controls and asks if they are collectively sufficient. Evaluate: (1) do they cover the same risk? (2) is there a detection latency gap? (3) are they formally documented? A combination of weak controls ≠ a strong compensating control.</div>'\n                    },\n                    {\n                        heading: \"Third-Party AI Risk — Vendor Management Checklist\",\n                        content: '\\n<div class=\"pv-def\"><strong>EU AI Act: Deployer Liability</strong> — Under the EU AI Act, the \"deployer\" (organization using AI) bears primary compliance responsibility, NOT the vendor/developer. Even if a vendor provides a \"fairness certificate,\" the deployer must conduct independent validation.</div>\\n<div class=\"pv-def\"><strong>Model Card</strong> — Documentation artifact disclosing: (1) intended use cases, (2) training data sources, (3) known limitations, (4) fairness metrics by protected class, (5) evaluation methodology. Absence = HIGH finding in AI audit.</div>\\n<div class=\"pv-trap\"><strong>TRAP:</strong> \"A vendor\\'s ISO 42001 certification means no further audit work is needed.\" → FALSE. Third-party certification reduces but does not eliminate audit procedures. You still need: scoping review, key control testing, ongoing monitoring, and contractual right-to-audit clause.</div>'\n                    }\n                ]\n            },\n            {\n                id: \"aigp-euai\",\n                icon: \"\\uD83C\\uDDEA\\uD83C\\uDDFA\",\n                title: \"EU AI Act — Deep Reference\",\n                weight: \"critical\",\n                subtitle: \"Risk tiers \\xb7 Prohibited uses \\xb7 Conformity assessment \\xb7 AIGP exam focus\",\n                category: \"EU AI Act\",\n                tag: \"trap\",\n                subsections: [\n                    {\n                        heading: \"Prohibited AI Practices — Article 5 (Must Memorize)\",\n                        content: '\\n<div class=\"pv-trap\"><strong>PROHIBITED (effective Aug 2026):</strong>\\n<br>• Subliminal manipulation techniques exploiting unconscious biases\\n<br>• Exploitation of vulnerabilities (age, disability, social situation)\\n<br>• Social scoring by public authorities for general purposes\\n<br>• Real-time remote biometric identification in public spaces (narrow LE exceptions only)\\n<br>• Predictive policing based solely on profiling (no observable facts)\\n<br>• Emotion recognition in workplace and educational institutions\\n<br>• Biometric categorization inferring sensitive attributes (race, political opinions, sexual orientation)\\n</div>\\n<div class=\"pv-tip\"><strong>Exam Tip:</strong> \"Biometric ID for border control\" = NOT prohibited (security exception). \"Biometric ID in shopping mall for marketing\" = PROHIBITED. The distinction is always the specific use case and authorization.</div>'\n                    },\n                    {\n                        heading: \"High-Risk AI Systems — Annex III (8 Categories)\",\n                        content: '\\n<table class=\"pv-table\">\\n  <thead><tr><th>#</th><th>Category</th><th>Examples</th><th>Key Obligation</th></tr></thead>\\n  <tbody>\\n    <tr class=\"pv-row-critical\"><td>1</td><td>Critical infrastructure</td><td>Water, energy, transport management</td><td>Risk management system + logging</td></tr>\\n    <tr class=\"pv-row-critical\"><td>2</td><td>Education/vocational</td><td>Student assessment, admission systems</td><td>Human oversight + transparency</td></tr>\\n    <tr class=\"pv-row-critical\"><td>3</td><td>Employment/HR</td><td>Hiring, performance evaluation, termination</td><td>Conformity assessment required</td></tr>\\n    <tr class=\"pv-row-high\"><td>4</td><td>Essential services</td><td>Credit scoring, insurance, emergency dispatch</td><td>Transparency to affected individuals</td></tr>\\n    <tr class=\"pv-row-high\"><td>5</td><td>Law enforcement</td><td>Polygraphs, risk assessment, crime prediction</td><td>Strict human oversight mandatory</td></tr>\\n    <tr><td>6</td><td>Migration/asylum</td><td>Document verification, risk assessment</td><td>Fundamental rights impact assessment</td></tr>\\n    <tr><td>7</td><td>Justice/democracy</td><td>Court outcome prediction, electoral influence</td><td>Highest oversight tier</td></tr>\\n    <tr><td>8</td><td>General purpose AI (GPAI)</td><td>LLMs with systemic risk (10\\xb2\\xb3 FLOPs+)</td><td>Separate GPAI Title</td></tr>\\n  </tbody>\\n</table>'\n                    }\n                ]\n            },\n            {\n                id: \"aaia-ethics\",\n                icon: \"⚖️\",\n                title: \"AI Ethics & Bias — Metrics & Frameworks\",\n                weight: \"high\",\n                subtitle: \"Fairness metrics \\xb7 Disparate impact \\xb7 Protected attributes \\xb7 Bias audit procedures\",\n                category: \"AI Fairness\",\n                tag: \"formula\",\n                subsections: [\n                    {\n                        heading: \"Fairness Metrics — Definitions and Formulas\",\n                        content: '\\n<div class=\"pv-formula\">\\n  <div class=\"pv-formula-title\">Disparate Impact Ratio (Four-Fifths Rule)</div>\\n  <div class=\"pv-formula-math\">DIR = Selection Rate (protected group) / Selection Rate (reference group)\\nDIR &lt; 0.8 → Adverse impact presumed (EEOC 4/5ths rule)\\nDIR = 1.0 → Perfect parity\\nDIR &gt; 1.0 → Positive discrimination toward protected group</div>\\n  <div class=\"pv-formula-example\">Example: Hiring AI approves 40% of minority applicants vs 65% for majority → DIR = 40/65 = 0.615 → Below 0.8 threshold → ADVERSE IMPACT finding required</div>\\n</div>\\n<div class=\"pv-formula\">\\n  <div class=\"pv-formula-title\">Key Fairness Metric Taxonomy</div>\\n  <div class=\"pv-formula-math\">Individual Fairness: Similar individuals get similar outcomes\\nGroup Fairness:\\n  Demographic Parity: P(ŷ=1|A=0) = P(ŷ=1|A=1)\\n  Equal Opportunity: TPR equal across groups\\n  Equalized Odds: TPR + FPR equal across groups\\nCounterfactual Fairness: Outcome unchanged if protected attribute were different</div>\\n</div>\\n<div class=\"pv-trap\"><strong>TRAP:</strong> \"Removing protected attributes from training data ensures fairness.\" → FALSE. Proxy variables (zip code, school name, surname) can encode protected attributes. This is called \\'proxy discrimination\\' — a HIGH finding in AI fairness audits. The exam tests this almost every session.</div>'\n                    },\n                    {\n                        heading: \"Bias Types — Taxonomy Tree\",\n                        content: '\\n<div class=\"pv-tree\">AI BIAS TAXONOMY\\n├── PRE-PROCESSING BIAS (Data-Level)\\n│   ├── Historical bias — training data reflects past discrimination\\n│   ├── Representation bias — underrepresentation of subgroups\\n│   ├── Measurement bias — inconsistent data collection across groups\\n│   └── Aggregation bias — ignoring subgroup heterogeneity\\n│\\n├── IN-PROCESSING BIAS (Model-Level)\\n│   ├── Optimization bias — loss function doesn\\'t penalize disparate outcomes\\n│   ├── Inductive bias — model architecture assumptions\\n│   └── Feedback loops — model outputs become future training data\\n│\\n└── POST-PROCESSING BIAS (Deployment-Level)\\n    ├── Evaluation bias — benchmark datasets not representative\\n    ├── Deployment drift — population shifts post-launch\\n    └── Human-in-loop bias — biased reviewers override model outputs</div>'\n                    }\n                ]\n            },\n            {\n                id: \"conflict-frameworks\",\n                icon: \"⚡\",\n                title: \"Conflicting Framework Resolution\",\n                weight: \"high\",\n                subtitle: \"GDPR vs retention \\xb7 HIPAA vs AI \\xb7 SOX vs AI models — Framework conflict exam scenarios\",\n                category: \"Framework Conflicts\",\n                tag: \"trap\",\n                subsections: [\n                    {\n                        heading: \"Common Framework Conflicts — Decision Matrix\",\n                        content: '\\n<table class=\"pv-table\">\\n  <thead><tr><th>Conflict</th><th>Framework A</th><th>Framework B</th><th>Resolution Approach</th><th>Exam Answer Pattern</th></tr></thead>\\n  <tbody>\\n    <tr class=\"pv-row-critical\"><td>Data retention vs privacy</td><td>Law enforcement: 7yr retention</td><td>GDPR Art.17: right to erasure</td><td>Pseudonymize + retain under Art.6(1)(c) legal obligation</td><td>Technical + legal solution satisfying BOTH</td></tr>\\n    <tr class=\"pv-row-high\"><td>Model explainability vs IP</td><td>GDPR Art.22: right to explanation</td><td>Trade secret protection</td><td>Functional explanation (not source code) per WP29</td><td>Proportionate disclosure — outcome not algorithm</td></tr>\\n    <tr><td>AI monitoring vs labor law</td><td>NIST AI RMF: monitor AI outputs</td><td>EU employee monitoring restrictions</td><td>Aggregate monitoring (not individual tracking); works council approval</td><td>Privacy-preserving monitoring design</td></tr>\\n    <tr><td>Audit access vs data minimization</td><td>Auditor needs model training data</td><td>GDPR minimization principle</td><td>Anonymized representative sample + certified deletion after audit</td><td>Minimum necessary + documented destruction</td></tr>\\n  </tbody>\\n</table>\\n<div class=\"pv-tip\"><strong>TIP:</strong> Exam conflict questions always have one answer that blindly prioritizes one framework over the other (wrong) and one that finds a technical + legal solution satisfying both (correct). Look for the \"both/and\" answer, not the \"either/or.\"</div>'\n                    }\n                ]\n            }\n        ],\n        flashcards: [\n            {\n                q: \"What is the NIST AI RMF Govern function's primary purpose?\",\n                a: \"Sets organization-wide policies, accountability structures, roles, and risk tolerances for responsible AI. The policy layer that all other functions operate within.\"\n            },\n            {\n                q: \"What does DIR < 0.8 mean in the EEOC Four-Fifths Rule?\",\n                a: \"Adverse impact is presumed. Selection rate for protected group is less than 80% of the reference group. Triggers investigation requirement.\"\n            },\n            {\n                q: \"Under EU AI Act, who bears compliance responsibility — developer or deployer?\",\n                a: \"The DEPLOYER (organization using the AI) bears primary compliance responsibility, even if they purchase AI from a vendor.\"\n            },\n            {\n                q: \"What is the diagnostic signature of CONCEPT drift vs DATA drift?\",\n                a: \"Concept drift: accuracy stays stable, precision/recall collapse (masked by class imbalance). Data drift: ALL metrics degrade uniformly.\"\n            },\n            {\n                q: \"Name the 4 NIST AI RMF core functions in order.\",\n                a: \"GOVERN → MAP → MEASURE → MANAGE. GOVERN is implemented first and is continuous. The functions are iterative, not sequential.\"\n            },\n            {\n                q: \"What is a 'proxy variable' in AI bias?\",\n                a: \"A variable that correlates with a protected attribute (e.g., zip code → race, school name → socioeconomic status) and can encode discrimination even when protected attributes are removed.\"\n            },\n            {\n                q: \"What triggers mandatory revalidation of an AI model per NIST AI RMF?\",\n                a: \"Performance metrics dropping >5% from validated baseline, significant feature drift (PSI > 0.2), or change in deployment context. Any combination triggers Manage function response.\"\n            },\n            {\n                q: \"What is the EU AI Act penalty for Tier 1 (prohibited) violations?\",\n                a: \"Up to €35 million OR 7% of global annual turnover, whichever is higher.\"\n            },\n            {\n                q: \"What must a Model Card contain?\",\n                a: \"Intended use cases, training data sources, known limitations, fairness metrics by protected class, evaluation methodology, and version history.\"\n            },\n            {\n                q: \"FAIR formula: What is Loss Event Frequency (LEF)?\",\n                a: \"LEF = Threat Event Frequency (TEF) \\xd7 Vulnerability. Example: 2 attempts/year \\xd7 50% success rate = 1.0 LEF.\"\n            },\n            {\n                q: \"When is a compensating control 'adequate' per audit standards?\",\n                a: \"When it: (1) addresses the same risk as the primary control, (2) provides comparable assurance level, (3) is formally documented with ownership, and (4) is independently tested.\"\n            },\n            {\n                q: \"What is the difference between ISO 42001 and NIST AI RMF applicability?\",\n                a: \"NIST AI RMF is voluntary, US-origin, no certification. ISO 42001 is a certifiable management standard (third-party audit), globally applicable, PDCA-structured.\"\n            }\n        ]\n    },\n    pj: {\n        title: \"Preparation Vault — ASCP MB (Pooja)\",\n        sub: \"Pre-built reference for ASCP Molecular Biology certification (May 2026) — all 6 domains with definitions, techniques, QC formulas, traps\",\n        quickTopics: [\n            \"PCR Variants Comparison\",\n            \"NGS Workflow Steps\",\n            \"CLIA QC Requirements\",\n            \"Sanger vs Next-Gen Sequencing\",\n            \"RNA Extraction Best Practices\",\n            \"ACMG Variant Classification\",\n            \"Westgard Rules\",\n            \"ddPCR Applications\"\n        ],\n        sections: [\n            {\n                id: \"ascp-pcr\",\n                icon: \"\\uD83E\\uDDEC\",\n                title: \"PCR Methodologies — Domain 3 (25% of Exam)\",\n                weight: \"critical\",\n                subtitle: \"Largest exam domain \\xb7 RT-PCR \\xb7 qPCR \\xb7 ddPCR \\xb7 Multiplex PCR \\xb7 Allele-specific PCR\",\n                category: \"PCR Methods\",\n                tag: \"formula\",\n                subsections: [\n                    {\n                        heading: \"PCR Variant Comparison — Master Table\",\n                        content: '\\n<table class=\"pv-table\">\\n  <thead><tr><th>PCR Type</th><th>Key Principle</th><th>Primary Application</th><th>Quantification?</th><th>Exam Hook</th></tr></thead>\\n  <tbody>\\n    <tr class=\"pv-row-critical\"><td>Real-time qPCR</td><td>Fluorescence measured each cycle; Ct value inversely proportional to starting template</td><td>Gene expression, pathogen load, copy number</td><td>Relative or absolute</td><td>Ct shift of 3.3 = 10-fold difference in template</td></tr>\\n    <tr class=\"pv-row-critical\"><td>ddPCR (Droplet Digital)</td><td>Sample partitioned into 20,000 droplets; Poisson statistics; endpoint detection</td><td>Rare variant detection, MRD, copy number</td><td>Absolute (no standard curve needed)</td><td>Gold standard for &lt;1% variant allele frequency</td></tr>\\n    <tr class=\"pv-row-high\"><td>RT-PCR</td><td>Reverse transcriptase converts RNA→cDNA first, then PCR amplification</td><td>RNA virus detection, gene expression from RNA</td><td>With real-time: yes</td><td>One-step vs two-step RT-PCR distinction</td></tr>\\n    <tr><td>Multiplex PCR</td><td>Multiple primer pairs in single reaction; each amplifies different target</td><td>Respiratory panels, STI panels, HLA typing</td><td>With qPCR: yes</td><td>Primer competition / nonspecific binding artifacts</td></tr>\\n    <tr><td>Allele-specific PCR</td><td>Primer 3\\' end perfectly matches one allele; mismatch = no amplification</td><td>SNP genotyping, drug resistance mutations</td><td>No (presence/absence)</td><td>Why 3\\' mismatch blocks amplification: no extension</td></tr>\\n    <tr><td>Nested PCR</td><td>Two sequential PCR rounds with inner primer set</td><td>Increase sensitivity for low-copy targets</td><td>No</td><td>Highest contamination risk — open-tube transfer</td></tr>\\n  </tbody>\\n</table>'\n                    },\n                    {\n                        heading: \"qPCR Fundamentals — Formulas and Ct Interpretation\",\n                        content: '\\n<div class=\"pv-formula\">\\n  <div class=\"pv-formula-title\">Ct Value Relationships</div>\\n  <div class=\"pv-formula-math\">Efficiency = (10^(-1/slope) - 1) \\xd7 100%\\nIdeal efficiency = 90–110% (slope: -3.1 to -3.6)\\nΔCt = Ct(target) - Ct(reference gene)\\nΔΔCt = ΔCt(sample) - ΔCt(calibrator)\\nFold change = 2^(-ΔΔCt)\\nCt 3.3 cycles difference = 10-fold concentration difference (at 100% efficiency)</div>\\n  <div class=\"pv-formula-example\">Example: ΔΔCt = 2.0 → Fold change = 2^(-2.0) = 0.25 → Target is 4\\xd7 downregulated vs calibrator</div>\\n</div>\\n<div class=\"pv-trap\"><strong>TRAP #1:</strong> \"Higher Ct = more template.\" → FALSE. Higher Ct = LESS starting template (more cycles needed to reach threshold). Classic direction reversal trap.</div>\\n<div class=\"pv-trap\"><strong>TRAP #2:</strong> \"ddPCR requires a standard curve.\" → FALSE. ddPCR uses Poisson statistics for absolute quantification — this is its key advantage over qPCR. No standard curve needed.</div>\\n<div class=\"pv-trap\"><strong>TRAP #3:</strong> \"Housekeeping gene Ct values should be identical across all samples.\" → Not exactly. Reference gene Ct should be stable (low CV) but minor variation is acceptable. Genes with Ct variation &gt;1 between conditions are poor reference choices.</div>'\n                    }\n                ]\n            },\n            {\n                id: \"ascp-ngs\",\n                icon: \"\\uD83D\\uDD2C\",\n                title: \"Sequencing Technologies — Domain 4 (20% of Exam)\",\n                weight: \"critical\",\n                subtitle: \"NGS workflow \\xb7 Variant calling \\xb7 File formats \\xb7 Sanger comparison \\xb7 Clinical interpretation\",\n                category: \"Sequencing\",\n                tag: \"formula\",\n                subsections: [\n                    {\n                        heading: \"NGS Workflow — Complete Pipeline\",\n                        content: '\\n<div class=\"pv-tree\">NGS CLINICAL WORKFLOW\\n├── 1. SAMPLE INPUT\\n│   ├── DNA/RNA extraction (check integrity: RIN ≥ 7 for RNA)\\n│   ├── Quantification: Qubit (fluorometric) or NanoDrop (UV — less sensitive)\\n│   └── Quality check: 260/280 ratio ~1.8 (DNA) or ~2.0 (RNA)\\n│\\n├── 2. LIBRARY PREPARATION\\n│   ├── Fragmentation (mechanical: sonication, or enzymatic)\\n│   ├── End repair + A-tailing\\n│   ├── Adapter ligation (adds flow cell binding sequences + index)\\n│   ├── Size selection (AMPure beads)\\n│   └── Library amplification (optional; adds duplicates)\\n│\\n├── 3. SEQUENCING\\n│   ├── Flow cell hybridization\\n│   ├── Bridge amplification → cluster generation\\n│   ├── Sequencing-by-synthesis (Illumina) — reversible terminators\\n│   └── Base calling → FASTQ output\\n│\\n├── 4. BIOINFORMATICS PIPELINE\\n│   ├── QC: FastQC → trim adapters (Trimmomatic/Cutadapt)\\n│   ├── Alignment: BWA-MEM → SAM/BAM output\\n│   ├── Mark duplicates: Picard MarkDuplicates\\n│   ├── Base quality score recalibration (BQSR — GATK)\\n│   ├── Variant calling: GATK HaplotypeCaller → VCF output\\n│   └── Annotation: VEP, ANNOVAR → clinical significance\\n│\\n└── 5. VARIANT INTERPRETATION\\n    ├── ACMG/AMP 5-tier classification (see below)\\n    ├── Population frequency check (gnomAD)\\n    └── Clinical report generation</div>'\n                    },\n                    {\n                        heading: \"ACMG/AMP Variant Classification — 5-Tier System\",\n                        content: '\\n<table class=\"pv-table\">\\n  <thead><tr><th>Class</th><th>Name</th><th>Reporting</th><th>Key Criteria</th></tr></thead>\\n  <tbody>\\n    <tr class=\"pv-row-critical\"><td>Class 5</td><td>Pathogenic</td><td>Report + genetic counseling</td><td>PVS1 (null variant in LOF gene) + PS/PM criteria</td></tr>\\n    <tr class=\"pv-row-critical\"><td>Class 4</td><td>Likely Pathogenic</td><td>Report with qualifier</td><td>≥90% probability pathogenic but insufficient for Class 5</td></tr>\\n    <tr class=\"pv-row-high\"><td>Class 3</td><td>Variant of Uncertain Significance (VUS)</td><td>Report as VUS; no clinical action</td><td>Insufficient evidence for classification; reclassify as evidence accrues</td></tr>\\n    <tr><td>Class 2</td><td>Likely Benign</td><td>May report; no clinical action</td><td>≥90% probability benign</td></tr>\\n    <tr><td>Class 1</td><td>Benign</td><td>Generally not reported</td><td>High population frequency + known benign functional data</td></tr>\\n  </tbody>\\n</table>\\n<div class=\"pv-trap\"><strong>TRAP:</strong> \"A VUS (Class 3) means the variant is harmless.\" → FALSE. VUS means INSUFFICIENT EVIDENCE to classify — it may be pathogenic or benign. Clinical labs must not use VUS for diagnostic decisions without additional evidence. Frequent reclassification exam scenario.</div>'\n                    },\n                    {\n                        heading: \"File Formats — Quick Reference\",\n                        content: '\\n<div class=\"pv-def\"><strong>FASTQ</strong> — Raw sequencing output. Contains: read sequence + quality scores (Phred, ASCII-encoded). Q30 = 99.9% base call accuracy. Q20 = 99%. Minimum Q20 per base for clinical NGS.</div>\\n<div class=\"pv-def\"><strong>SAM/BAM</strong> — Sequence Alignment Map / Binary Alignment Map. Read sequences aligned to reference genome. BAM is compressed binary SAM. CRAM = even more compressed.</div>\\n<div class=\"pv-def\"><strong>VCF</strong> — Variant Call Format. Lists all variants detected vs reference. Fields: CHROM, POS, ID, REF, ALT, QUAL, FILTER, INFO, FORMAT. GT field = genotype (0/0 = homozygous ref, 0/1 = het, 1/1 = homozygous alt).</div>\\n<div class=\"pv-tip\"><strong>Exam tip:</strong> Know the transformation: FASTQ → (alignment) → BAM → (variant calling) → VCF → (annotation) → clinical report. Each step has a corresponding tool: BWA-MEM, GATK, VEP/ANNOVAR.</div>'\n                    }\n                ]\n            },\n            {\n                id: \"ascp-extraction\",\n                icon: \"\\uD83E\\uDDEA\",\n                title: \"Nucleic Acid Extraction & QC — Domain 2\",\n                weight: \"high\",\n                subtitle: \"Extraction methods \\xb7 QC metrics \\xb7 Inhibitors \\xb7 Storage conditions\",\n                category: \"Nucleic Acids\",\n                tag: \"formula\",\n                subsections: [\n                    {\n                        heading: \"Extraction Method Comparison\",\n                        content: '\\n<table class=\"pv-table\">\\n  <thead><tr><th>Method</th><th>Principle</th><th>Best For</th><th>Key Limitation</th></tr></thead>\\n  <tbody>\\n    <tr class=\"pv-row-critical\"><td>Silica column (spin column)</td><td>DNA binds silica under chaotropic + low pH; elutes with low-salt buffer or water</td><td>High-purity DNA/RNA from most samples</td><td>Lower yield vs precipitation; can lose small fragments</td></tr>\\n    <tr class=\"pv-row-high\"><td>Magnetic bead</td><td>DNA/RNA binds paramagnetic beads; magnetic separation removes contaminants</td><td>Automation, blood, FFPE, small volumes</td><td>Higher cost; bead carryover can inhibit downstream assays</td></tr>\\n    <tr><td>Phenol-chloroform</td><td>Phase separation: DNA in aqueous, proteins in organic phase</td><td>High-molecular-weight DNA, research</td><td>Toxic (phenol), manual, not automation-friendly</td></tr>\\n    <tr><td>Chelex resin</td><td>Chelates metal ions that inhibit PCR; heat lysis releases DNA</td><td>Forensic (touch DNA, old samples)</td><td>Single-stranded DNA (heat denaturation); not for restriction digestion</td></tr>\\n  </tbody>\\n</table>\\n<div class=\"pv-formula\">\\n  <div class=\"pv-formula-title\">Purity Ratios — NanoDrop Interpretation</div>\\n  <div class=\"pv-formula-math\">A260/A280 ratio:\\n  DNA: ~1.8 (acceptable: 1.7–2.0)\\n  RNA: ~2.0 (acceptable: 1.9–2.1)\\n  &lt;1.7 → protein contamination (absorbs at 280nm)\\n  &gt;2.1 → RNA contamination in DNA prep\\n\\nA260/A230 ratio:\\n  Acceptable: 2.0–2.2\\n  &lt;1.8 → chaotropic salt, phenol, or polysaccharide contamination\\n  Low A260/A230 = most common PCR inhibitor source</div>\\n  <div class=\"pv-formula-example\">TRAP: A260/A280 = 2.2 on a DNA sample. Most students say \"RNA contamination.\" But first check the A260/A230 — if that\\'s fine, the 2.2 may indicate slightly alkaline elution buffer (acceptable).</div>\\n</div>'\n                    }\n                ]\n            },\n            {\n                id: \"ascp-qc\",\n                icon: \"\\uD83D\\uDCCA\",\n                title: \"QC, Lab Ops & CLIA Regulations — Domain 6\",\n                weight: \"high\",\n                subtitle: \"Westgard rules \\xb7 CLIA requirements \\xb7 Proficiency testing \\xb7 Delta checks \\xb7 QC frequency\",\n                category: \"Lab QC\",\n                tag: \"formula\",\n                subsections: [\n                    {\n                        heading: \"Westgard Rules — Complete Reference\",\n                        content: '\\n<div class=\"pv-formula\">\\n  <div class=\"pv-formula-title\">Westgard Multi-Rules for QC Failure Detection</div>\\n  <div class=\"pv-formula-math\">1₂s — WARNING: 1 QC value exceeds \\xb12SD (evaluate further; do not reject alone)\\n1₃s — REJECTION: 1 QC value exceeds \\xb13SD → reject run (random error)\\n2₂s — REJECTION: 2 consecutive QC values exceed +2SD or -2SD on same side → systematic error\\nR₄s — REJECTION: 1 QC value exceeds +2SD AND another exceeds -2SD in same run → random error\\n4₁s — REJECTION: 4 consecutive values on same side of mean (all +1SD or all -1SD) → systematic shift\\n10x  — REJECTION: 10 consecutive values on same side of mean → long-term systematic drift</div>\\n  <div class=\"pv-formula-example\">Memory aid: \"1 warning, reject with 1-3, 2-2, R-4, 4-1, or 10x.\" The R4s rule is the most commonly tested — it catches random error across ONE run.</div>\\n</div>\\n<div class=\"pv-trap\"><strong>TRAP:</strong> \"If only one QC control fails, the entire run must be repeated.\" → The 1₂s rule is a WARNING only. You do NOT reject the run on 1₂s alone — you evaluate using the multi-rule system. Automatic rejection only occurs on 1₃s, 2₂s, R₄s, 4₁s, or 10ₓ.</div>'\n                    },\n                    {\n                        heading: \"CLIA Requirements — Critical Reference Points\",\n                        content: '\\n<div class=\"pv-def\"><strong>CLIA (Clinical Laboratory Improvement Amendments)</strong> — Federal law regulating all US clinical laboratories performing testing on human specimens. Administered by CMS. Three levels: Certificate of Waiver, Certificate of PPM Procedures, Certificate of Compliance/Accreditation.</div>\\n<table class=\"pv-table\">\\n  <thead><tr><th>CLIA Requirement</th><th>Frequency/Threshold</th><th>Consequence of Non-Compliance</th></tr></thead>\\n  <tbody>\\n    <tr class=\"pv-row-critical\"><td>Proficiency Testing (PT)</td><td>3 times/year per analyte; ≥80% score required</td><td>Suspension of testing for that analyte</td></tr>\\n    <tr class=\"pv-row-high\"><td>QC frequency (non-waived)</td><td>Minimum 2 levels per day of testing (high + low)</td><td>Finding on inspection; invalidate results</td></tr>\\n    <tr><td>Personnel qualifications (High complexity)</td><td>Laboratory Director: MD/PhD or doctoral degree + board certified</td><td>CLIA certificate revocation</td></tr>\\n    <tr><td>Calibration verification</td><td>Every 6 months or when reagent lot changes</td><td>Results unreliable; may require repeat testing</td></tr>\\n    <tr><td>Delta check</td><td>Compare current vs previous patient result; flag if outside expected delta</td><td>Specimen mix-up detection; repeat required</td></tr>\\n  </tbody>\\n</table>\\n<div class=\"pv-trap\"><strong>TRAP:</strong> \"Proficiency testing samples must be tested with extra care.\" → ILLEGAL. PT samples must be tested exactly as patient samples — same personnel, same process, no consultation with other labs. Intentional manipulation = CLIA violation + possible exclusion from Medicare/Medicaid.</div>'\n                    }\n                ]\n            },\n            {\n                id: \"ascp-expression\",\n                icon: \"\\uD83D\\uDCC8\",\n                title: \"Gene Expression & Epigenetics — Domain 5\",\n                weight: \"medium\",\n                subtitle: \"RNA-seq workflow \\xb7 scRNA-seq \\xb7 Epigenetic modifications \\xb7 ChIP-seq \\xb7 ATAC-seq\",\n                category: \"Gene Expression\",\n                tag: \"formula\",\n                subsections: [\n                    {\n                        heading: \"RNA-seq vs scRNA-seq — Key Distinctions\",\n                        content: '\\n<table class=\"pv-table\">\\n  <thead><tr><th>Dimension</th><th>Bulk RNA-seq</th><th>scRNA-seq</th></tr></thead>\\n  <tbody>\\n    <tr><td>Input</td><td>Pooled RNA from thousands of cells</td><td>Single-cell suspension; ~1,000–10,000 cells captured</td></tr>\\n    <tr class=\"pv-row-high\"><td>Resolution</td><td>Average expression across all cells</td><td>Cell-by-cell expression profile; reveals heterogeneity</td></tr>\\n    <tr><td>Sensitivity</td><td>High (many cells pool signal)</td><td>Lower per cell (high dropout rate for lowly expressed genes)</td></tr>\\n    <tr><td>Cost</td><td>Lower (~$300–500/sample)</td><td>Higher (~$1,000–3,000/sample on 10x platform)</td></tr>\\n    <tr class=\"pv-row-critical\"><td>Key use case</td><td>DEG analysis between conditions; bulk comparison</td><td>Cell type identification, trajectory analysis, rare cell discovery</td></tr>\\n    <tr><td>Normalization</td><td>DESeq2, edgeR (negative binomial)</td><td>Seurat SCTransform; log-normalization</td></tr>\\n  </tbody>\\n</table>\\n<div class=\"pv-def\"><strong>Dropout (scRNA-seq)</strong> — Zero counts for a gene in a cell when the gene IS expressed, due to capture inefficiency. Typical dropout rates: 80–95% in 10x Chromium. Imputation methods (MAGIC, scImpute) address this but introduce their own biases.</div>'\n                    },\n                    {\n                        heading: \"Epigenetic Modification Summary\",\n                        content: '\\n<div class=\"pv-def\"><strong>DNA Methylation</strong> — Addition of CH₃ to cytosine at CpG dinucleotides. Promoter methylation → gene silencing. Bisulfite sequencing converts unmethylated C→U (then T in sequencing), methylated C remains C. WGBS = whole-genome bisulfite sequencing.</div>\\n<div class=\"pv-def\"><strong>Histone Modifications</strong> — Post-translational modifications of histone tails. H3K4me3 = active promoter. H3K27me3 = repressed. H3K36me3 = actively transcribed gene body. H3K27ac = active enhancer. Detected by ChIP-seq.</div>\\n<div class=\"pv-def\"><strong>ChIP-seq</strong> — Chromatin Immunoprecipitation sequencing. Cross-link protein-DNA, sonicate, immunoprecipitate with antibody, sequence. Input control essential for peak calling normalization.</div>\\n<div class=\"pv-trap\"><strong>TRAP:</strong> \"Promoter methylation always silences gene expression.\" → Generally true but NOT always. Gene body methylation is associated with ACTIVE transcription. Context (location relative to gene) determines effect. Exam will test CpG island (promoter) vs gene body methylation distinction.</div>'\n                    }\n                ]\n            }\n        ],\n        flashcards: [\n            {\n                q: \"What does a Ct value of 3.3 cycles difference represent in qPCR?\",\n                a: \"A 10-fold (one log) difference in starting template concentration. Higher Ct = less template. Ct increases as template decreases.\"\n            },\n            {\n                q: \"What is the key advantage of ddPCR over qPCR?\",\n                a: \"Absolute quantification without a standard curve, using Poisson statistics. Gold standard for rare variants (<1% VAF) and minimal residual disease (MRD) detection.\"\n            },\n            {\n                q: \"ACMG Class 3 (VUS) — what does this mean clinically?\",\n                a: \"Variant of Uncertain Significance — INSUFFICIENT evidence to classify as pathogenic or benign. Cannot be used for clinical decision-making without additional evidence.\"\n            },\n            {\n                q: \"What does an A260/A280 ratio of 1.4 indicate for a DNA sample?\",\n                a: \"Protein contamination (absorbs at 280nm). Acceptable range for DNA is 1.7–2.0. Below 1.7 indicates protein/aromatic compound contamination.\"\n            },\n            {\n                q: \"The 1₂s Westgard rule — action required?\",\n                a: \"WARNING ONLY. One QC value exceeding \\xb12SD is a warning flag — do NOT reject the run. Evaluate further using multi-rule system before deciding.\"\n            },\n            {\n                q: \"What NGS file format contains raw reads with quality scores?\",\n                a: \"FASTQ. Q30 = 99.9% base call accuracy. Each base has a Phred quality score. Minimum Q20 acceptable for clinical sequencing.\"\n            },\n            {\n                q: \"Bisulfite sequencing converts what to what?\",\n                a: \"Unmethylated cytosine (C) → uracil (U), which reads as thymine (T) after PCR. Methylated cytosine remains as C. This allows discrimination of methylated vs unmethylated sites.\"\n            },\n            {\n                q: \"CLIA proficiency testing — what score is required?\",\n                a: \"≥80% (4 out of 5 challenges per analyte per testing event). PT must be conducted 3 times per year. Failure triggers suspension of that test.\"\n            },\n            {\n                q: \"What is the H3K27me3 histone modification associated with?\",\n                a: \"Gene repression / silenced chromatin. H3K4me3 = active promoter. H3K27ac = active enhancer. H3K36me3 = active transcription elongation.\"\n            },\n            {\n                q: \"Nested PCR — what is the primary clinical concern?\",\n                a: \"High contamination risk due to open-tube transfer between first and second PCR. Requires strict physical separation of pre- and post-amplification areas. Highest contamination risk of all PCR methods.\"\n            },\n            {\n                q: \"What does the R₄s Westgard rule detect?\",\n                a: \"Random error within a single run. One QC exceeds +2SD AND another exceeds -2SD in the same run. The 4-SD range between the two QC values triggers run rejection.\"\n            },\n            {\n                q: \"scRNA-seq dropout — what causes it and what is the typical rate?\",\n                a: \"Stochastic failure to capture/amplify low-abundance transcripts from a single cell. Typical dropout rate: 80–95% on 10x Chromium platform. Leads to zero-inflated count matrices.\"\n            }\n        ]\n    }\n};\n\n\n;\n    // Wrapped in an IIFE to avoid polluting the global scope\n    ;\n    (function () {\n        var _a, _b;\n        // Legacy CSS implementations will `eval` browser code in a Node.js context\n        // to extract CSS. For backwards compatibility, we need to check we're in a\n        // browser context before continuing.\n        if (typeof self !== 'undefined' &&\n            // AMP / No-JS mode does not inject these helpers:\n            '$RefreshHelpers$' in self) {\n            // @ts-ignore __webpack_module__ is global\n            var currentExports = module.exports;\n            // @ts-ignore __webpack_module__ is global\n            var prevSignature = (_b = (_a = module.hot.data) === null || _a === void 0 ? void 0 : _a.prevSignature) !== null && _b !== void 0 ? _b : null;\n            // This cannot happen in MainTemplate because the exports mismatch between\n            // templating and execution.\n            self.$RefreshHelpers$.registerExportsForReactRefresh(currentExports, module.id);\n            // A module can be accepted automatically based on its exports, e.g. when\n            // it is a Refresh Boundary.\n            if (self.$RefreshHelpers$.isReactRefreshBoundary(currentExports)) {\n                // Save the previous exports signature on update so we can compare the boundary\n                // signatures. We avoid saving exports themselves since it causes memory leaks (https://github.com/vercel/next.js/pull/53797)\n                module.hot.dispose(function (data) {\n                    data.prevSignature =\n                        self.$RefreshHelpers$.getRefreshBoundarySignature(currentExports);\n                });\n                // Unconditionally accept an update to this module, we'll check if it's\n                // still a Refresh Boundary later.\n                // @ts-ignore importMeta is replaced in the loader\n                module.hot.accept();\n                // This field is set when the previous version of this module was a\n                // Refresh Boundary, letting us know we need to check for invalidation or\n                // enqueue an update.\n                if (prevSignature !== null) {\n                    // A boundary can become ineligible if its exports are incompatible\n                    // with the previous exports.\n                    //\n                    // For example, if you add/remove/change exports, we'll want to\n                    // re-execute the importing modules, and force those components to\n                    // re-render. Similarly, if you convert a class component to a\n                    // function, we want to invalidate the boundary.\n                    if (self.$RefreshHelpers$.shouldInvalidateReactRefreshBoundary(prevSignature, self.$RefreshHelpers$.getRefreshBoundarySignature(currentExports))) {\n                        module.hot.invalidate();\n                    }\n                    else {\n                        self.$RefreshHelpers$.scheduleUpdate();\n                    }\n                }\n            }\n            else {\n                // Since we just executed the code for the module, it's possible that the\n                // new exports made it ineligible for being a boundary.\n                // We only care about the case when we were _previously_ a boundary,\n                // because we already accepted this update (accidental side effect).\n                var isNoLongerABoundary = prevSignature !== null;\n                if (isNoLongerABoundary) {\n                    module.hot.invalidate();\n                }\n            }\n        }\n    })();\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///./src/data/prepVault.ts\n"));

